using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_5dd0623d976045adb695ede6795b7ad5.Client;

namespace sv_5dd0623d976045adb695ede6795b7ad5.Auth;

// Server-side provider that returns a hardcoded authenticated user and
// persists the identity via PersistentComponentState so the WebAssembly
// runtime receives it after the interactive handoff.
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _state;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState state)
    {
        _state = state;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return Task.FromResult(new AuthenticationState(new ClaimsPrincipal(identity)));
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authenticationStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authenticationStateTask ?? GetAuthenticationStateAsync();
        var principal = (await authState).User;

        if (principal.Identity?.IsAuthenticated != true)
            return;

        var email = principal.FindFirst(ClaimTypes.Email)?.Value ?? "";
        var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

        _state.PersistAsJson(nameof(UserInfo), new UserInfo
        {
            Email = email,
            Roles = roles,
        });
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

